<#
.SYNOPSIS
    MDE Live Response browser history collector using NirSoft BrowsingHistoryView.

.DESCRIPTION
    Drops the correct-architecture BrowsingHistoryView.exe to disk, runs it against
    all user profiles on the host, exports CSV + HTML, compresses the output, and
    prints the resulting zip path for retrieval via Live Response 'getfile'.

    Output is written to a deterministic path so it can be retrieved
    non-interactively via the MDE Live Response API (RunScript + GetFile chain):
        C:\temp\BrowserHistory\browser_history.zip

    Interactive Live Response usage:
        run Invoke-MDEBrowserHistoryCollection.ps1
        getfile "C:\temp\BrowserHistory\browser_history.zip"

    Automated usage: see Invoke-MDEBrowserHistoryCollection.Orchestrate.ps1

.NOTES
    Tool : NirSoft BrowsingHistoryView (https://www.nirsoft.net/utils/browsing_history_view.html)
    Author context : defensive DFIR collection
#>

[CmdletBinding()]
param(
    [string] $WorkDir = 'C:\temp\BrowserHistory',
    # 1 = all users on this system. 2 = current user only. See BHV readme.
    [int]    $HistorySource = 1,
    # 1 = any date, 2 = last N days, 4 = custom range. See BHV readme.
    [int]    $VisitTimeFilterType = 1,
    # Only used when VisitTimeFilterType = 2 or 3 (days / hours back).
    [int]    $VisitTimeFilterValue = 0
)

$ErrorActionPreference = 'Stop'
$ProgressPreference    = 'SilentlyContinue'

# Live Response runs as SYSTEM; TLS defaults can trip up downloads if added later.
[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12

$Hostname  = $env:COMPUTERNAME
$Timestamp = Get-Date -Format 'yyyyMMdd-HHmmss'
# Deterministic zip path. Required so the MDE Live Response API 'GetFile' step
# can reference the output without pre-querying the target host. Hostname and
# collection time are preserved inside the zip via manifest.txt and inner CSV/
# HTML filenames.
$ZipPath   = Join-Path $WorkDir 'browser_history.zip'

Write-Host "=== MDE Browser History Collector ==="
Write-Host "Host      : $Hostname"
Write-Host "Timestamp : $Timestamp"
Write-Host "WorkDir   : $WorkDir"

