QURESU5HWFhQQURESU5HUEFERA==
'@

# -----------------------------------------------------------------------------
# Stage working directory
# -----------------------------------------------------------------------------
if (Test-Path $WorkDir) {
    Remove-Item $WorkDir -Recurse -Force -ErrorAction SilentlyContinue
}
New-Item -ItemType Directory -Path $WorkDir -Force | Out-Null

# -----------------------------------------------------------------------------
# Pick the right binary for the OS architecture. Live Response on a 64-bit host
# runs 64-bit PowerShell, so Is64BitOperatingSystem is authoritative here.
# -----------------------------------------------------------------------------
$ExePath = Join-Path $WorkDir 'BrowsingHistoryView.exe'
if ([Environment]::Is64BitOperatingSystem) {
    Write-Host "Arch      : x64"
    [IO.File]::WriteAllBytes($ExePath, [Convert]::FromBase64String(($BhvX64Base64 -replace '\s','')))
    $ExpectedHash = $BhvX64Sha256
} else {
    Write-Host "Arch      : x86"
    [IO.File]::WriteAllBytes($ExePath, [Convert]::FromBase64String(($BhvX86Base64 -replace '\s','')))
    $ExpectedHash = $BhvX86Sha256
}

# Integrity check - protects against transport corruption of the pasted base64.
$ActualHash = (Get-FileHash -Path $ExePath -Algorithm SHA256).Hash
if ($ActualHash -ne $ExpectedHash) {
    Write-Host "[!] SHA256 mismatch. Expected $ExpectedHash, got $ActualHash"
    Remove-Item $ExePath -Force -ErrorAction SilentlyContinue
    throw "BrowsingHistoryView.exe integrity check failed."
}
Write-Host "SHA256 OK : $ActualHash"

# -----------------------------------------------------------------------------
# Run BrowsingHistoryView - once for CSV (machine-parseable), once for HTML (analyst-friendly)
# -----------------------------------------------------------------------------
$CsvPath  = Join-Path $WorkDir ("{0}_browser_history.csv"  -f $Hostname)
$HtmlPath = Join-Path $WorkDir ("{0}_browser_history.html" -f $Hostname)

$CommonArgs = @(
    '/HistorySource',        $HistorySource,
    '/VisitTimeFilterType',  $VisitTimeFilterType,
    '/LoadIE',     '1',
    '/LoadFirefox','1',
    '/LoadChrome', '1',
    '/LoadSafari', '1',
    '/StopIECacheTask', '0'
)
if ($VisitTimeFilterType -in 2,3) {
    $CommonArgs += @('/VisitTimeFilterValue', $VisitTimeFilterValue)
}

Write-Host "Running   : BrowsingHistoryView (CSV export)..."
$p1 = Start-Process -FilePath $ExePath `
    -ArgumentList ($CommonArgs + @('/scomma', "`"$CsvPath`"")) `
    -WindowStyle Hidden -Wait -PassThru
Write-Host "Exit code : $($p1.ExitCode)"

Write-Host "Running   : BrowsingHistoryView (HTML export)..."
$p2 = Start-Process -FilePath $ExePath `
    -ArgumentList ($CommonArgs + @('/shtml', "`"$HtmlPath`"")) `
    -WindowStyle Hidden -Wait -PassThru
Write-Host "Exit code : $($p2.ExitCode)"

# Manifest preserves host/time context since the zip filename is deterministic.
$ManifestPath = Join-Path $WorkDir 'manifest.txt'
@"
ComputerName       : $Hostname
CollectionTime     : $Timestamp ($([DateTimeOffset]::Now.ToString('o')))
Architecture       : $(if ([Environment]::Is64BitOperatingSystem) { 'x64' } else { 'x86' })
HistorySource      : $HistorySource
VisitTimeFilter    : $VisitTimeFilterType (value=$VisitTimeFilterValue)
Tool               : NirSoft BrowsingHistoryView
ToolSHA256         : $ActualHash
CollectorScript    : $($MyInvocation.MyCommand.Name)
RunAs              : $([System.Security.Principal.WindowsIdentity]::GetCurrent().Name)
"@ | Out-File -FilePath $ManifestPath -Encoding UTF8

# -----------------------------------------------------------------------------
# Package results. Binary is excluded from the zip - it's tooling, not evidence.
# -----------------------------------------------------------------------------
$ToZip = @($CsvPath, $HtmlPath, $ManifestPath) | Where-Object { Test-Path $_ }
if (-not $ToZip) {
    Remove-Item $ExePath -Force -ErrorAction SilentlyContinue
    throw "No output produced by BrowsingHistoryView - nothing to collect."
}

Compress-Archive -Path $ToZip -DestinationPath $ZipPath -Force
$ZipSize = (Get-Item $ZipPath).Length

# -----------------------------------------------------------------------------
# Cleanup - remove the binary and the loose exports, leave only the zip.
# Reason: reduces footprint and avoids leaving third-party tooling on the host.
# -----------------------------------------------------------------------------
Remove-Item $ExePath      -Force -ErrorAction SilentlyContinue
Remove-Item $CsvPath      -Force -ErrorAction SilentlyContinue
Remove-Item $HtmlPath     -Force -ErrorAction SilentlyContinue
Remove-Item $ManifestPath -Force -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== Collection complete ==="
Write-Host "Output    : $ZipPath"
Write-Host "Size      : $ZipSize bytes"
Write-Host ""
Write-Host "Retrieve via Live Response console:"
Write-Host "    getfile `"$ZipPath`""
Write-Host "Or orchestrate via API (RunScript + GetFile chain):"
Write-Host "    Invoke-MDEBrowserHistoryCollection.Orchestrate.ps1 -DeviceId <id>"

# Emit zip path as the last object so Live Response captures it cleanly.
[pscustomobject]@{
    ComputerName = $Hostname
    ZipPath      = $ZipPath
    ZipSize      = $ZipSize
    Timestamp    = $Timestamp
} | Format-List
